const ll LLinf = 1e18;
const ld PI = acos(-1);

int n;
deque<ll> v;
ll dp[N];

ll calc_cost(vector<ll> a) {
    sort(all(a));
    return a.back() - a.front();
}

ll fun(int i) {
    if (i > n)return LLinf;
    if (i == n) return 0;
    ll &ret = dp[i];
    if (~ret) return ret;
    ret = LLinf;
    if (i + 1 < n) {
        ll cost = calc_cost(vector({v[i], v[i + 1]}));
        ret = min(ret, cost + fun(i + 2));
    }
    if (i + 2 < n) {
        ll cost = calc_cost(vector({v[i], v[i + 1], v[i + 2]}));
        ret = min(ret, cost + fun(i + 3));
    }

    return ret;

}


