    for(int i=l-1;i>=0;i--){
        int curex=1e15;
        if(i+1==l){curex=0;}
        if(i+2<=l){curex=dp[i+2];}
        dp[i]=min(dp[i],abs(v[i]-v[i+1])+curex);

